import pytest
from hex_to_rgb import hex_to_rgb


# ---------------------------------------------------------------------------
# Happy path tests
# ---------------------------------------------------------------------------

class TestHappyPath:
    def test_black(self):
        assert hex_to_rgb("#000000") == (0, 0, 0)

    def test_white(self):
        assert hex_to_rgb("#ffffff") == (255, 255, 255)

    def test_red(self):
        assert hex_to_rgb("#ff0000") == (255, 0, 0)

    def test_green(self):
        assert hex_to_rgb("#00ff00") == (0, 255, 0)

    def test_blue(self):
        assert hex_to_rgb("#0000ff") == (0, 0, 255)

    def test_arbitrary_color(self):
        assert hex_to_rgb("#1a2b3c") == (26, 43, 60)

    def test_returns_tuple(self):
        result = hex_to_rgb("#ffffff")
        assert isinstance(result, tuple)

    def test_tuple_has_three_elements(self):
        result = hex_to_rgb("#aabbcc")
        assert len(result) == 3

    def test_uppercase_hex(self):
        assert hex_to_rgb("#FF0000") == (255, 0, 0)

    def test_mixed_case_hex(self):
        assert hex_to_rgb("#fF00Ff") == (255, 0, 255)

    def test_without_hash_prefix(self):
        """Function should work when the '#' prefix is omitted."""
        assert hex_to_rgb("ff0000") == (255, 0, 0)

    def test_mid_range_values(self):
        assert hex_to_rgb("#7f7f7f") == (127, 127, 127)

    def test_each_channel_is_int(self):
        r, g, b = hex_to_rgb("#1a2b3c")
        assert all(isinstance(channel, int) for channel in (r, g, b))

    @pytest.mark.parametrize("hex_color, expected", [
